	image = (fp*)malloc(sizeof(fp) * Ne);

	resize(	image_ori,
				image_ori_rows,
				image_ori_cols,
				image,
				Nr,
				Nc,
				1);

	r1     = 0;											
	r2     = Nr - 1;									
	c1     = 0;											
	c2     = Nc - 1;									

	NeROI = (r2-r1+1)*(c2-c1+1);											

	mem_size_i = sizeof(int) * Nr;											
	iN = (int *)malloc(mem_size_i) ;										
	iS = (int *)malloc(mem_size_i) ;										
	mem_size_j = sizeof(int) * Nc;											
	jW = (int *)malloc(mem_size_j) ;										
	jE = (int *)malloc(mem_size_j) ;										

	for (i=0; i<Nr; i++) {
		iN[i] = i-1;														
		iS[i] = i+1;														
	}
	for (j=0; j<Nc; j++) {
		jW[j] = j-1;														
		jE[j] = j+1;														
	}

	iN[0]    = 0;															
	iS[Nr-1] = Nr-1;														
	jW[0]    = 0;															
	jE[Nc-1] = Nc-1;														

	kernel_gpu_opencl_wrapper(	image,										
								Nr,											
								Nc,											
								Ne,											
								niter,										
								lambda,										
								NeROI,										
								iN,
								iS,
								jE,
								jW,
								iter,										
								mem_size_i,
								mem_size_j);

	write_graphics(	"./output/image_out.pgm",
					image,
					Nr,
					Nc,
					1,
					255);

	free(image_ori);
	free(image);
	free(iN); 
	free(iS); 
	free(jW); 
	free(jE);

	return 0;
}
